import styled from "styled-components"
import Typewriter from 'typewriter-effect';

import Brand from "./brand";

import github from '../../img/LandingPage/github.svg'
import mail from '../../img/LandingPage/mail.svg'

const getRandomNumberInRange = (min, max) => {
  return Math.ceil((Math.random() * (max - min) + min));
}

const misSpell = (string) => {
  const position = getRandomNumberInRange(1, string.length - 1)

  const misSpelledString = `${string.slice(0, position)}bd`
  const rest = string.slice(position, string.length)

  return [ misSpelledString, rest ]
}

const LandingPage = () => {
  const [ misSpelledString, rest ] = misSpell("Adam Jałocha")

  return (
    <Container>
      <Brand />
      <Introduction>
        <Name>
          <Typewriter
            onInit={(typewriter) => {
              typewriter
                .changeDelay(80)
                .typeString(misSpelledString)
                .deleteChars(2)
                .typeString(rest)
                .pauseFor(1000)
                .callFunction((target) => target.elements.cursor.style.display = "none")
                .start()
            }}
          />
        </Name>
        {/* <hr /> */}
        <Description>
          I am a front-end developer who use react to accomplish things.
        </Description>
      </Introduction>
      <More> More </More>

      <QuickContact>
        <img src={github} alt="github logo" />
        <img src={mail} alt="mail icon" />
      </QuickContact>
    </Container>
  )
}

const Container = styled.section`
  width: 100vw;
  height: 100vh;
  background: black;
  color: white;

  display: grid;
  grid-template: auto 1fr auto / auto auto;
  align-items: center;
  justify-content: space-between;

  font-family: Rubik;

  & > * {
    padding-left: 4em;
  }
`

const Introduction = styled.div`
  font-size: 3em;
  padding: 0 0 0em 3em;

  position: relative;
  display: flex;
  flex-direction: column;
  row-gap: 0.3em;

  & > hr {
    position: absolute;
    width: 120%;
    left: 0;
    top: 1em;
  }
`

const Name = styled.span`
  font-weight: 600;
  letter-spacing: 2px;
  /* text-decoration: underline; */
  /* border-bottom: 2px solid white; */
`

const Description = styled.span`
  font-size: 0.3em;
  font-weight: 100;
  max-width: 50ch;
  letter-spacing: 1px;
`

const More = styled.span`
  padding-bottom: 2em;
`

const QuickContact = styled.div`
  padding: 1em;
  grid-column: 2;
  grid-row: 1/4;

  & img {
    filter: invert(1)
  }
`

export default LandingPage
